tab_text, tab_image, tab_audio, tab_video = st.tabs(
    [
        "📝 Text Classification",
        "🖼️ Image Classification",
        "🎵 Audio Classification",
        "📹 Video Classification",
    ]
)

with tab_text:
    st.header("Text Classification")

    col1, col2 = st.columns([1, 2], gap="large")

    with col1:
        st.subheader("Configuration")
        encoder_name_t = st.text_input(
            "Encoder Name",
            "sentence-transformers/all-MiniLM-L6-v2",
            key="en_t",
            disabled=True,
        )
        encoder_class_t = st.text_input(
            "Encoder Class", "sentence-transformer", key="ec_t", disabled=True
        )
        prompt_template_t = st.text_input(
            "Prompt Template", "This text is {}", key="pt_t"
        )

        st.markdown("**Label Verbalizations (JSON format)**")
        labels_input_t = st.text_area(
            "Labels mapping",
            '{\n  "positive": "really positive",\n  "negative": "really negative"\n}',
            height=100,
            key="lbl_t",
        )

        st.markdown("**Data Inputs**")
        texts_input = st.text_area(
            "Texts (one per line)",
            "I'm happy\nI'm sad\nYou're strong\nFuck you.",
            height=120,
        )
        truths_input_t = st.text_input(
            "Ground Truth Labels (Indices for Training)", "0, 1, 0, 1"
        )

        run_text = st.button("🚀 Run Text Pipelines", type="primary")

    with col2:
        st.subheader("Execution & Results")
        if run_text:
            with st.spinner("Processing Text Pipeline..."):
                try:
                    label_verbalizations = json.loads(labels_input_t)
                    texts = [
                        t.strip() for t in texts_input.split("\n") if t.strip()
                    ]
                    truths = [
                        int(x.strip()) for x in truths_input_t.split(",")
                    ]

                    # Base Initialization
                    pipeline = TextPipeline(
                        encoder_name_t,
                        encoder_class_t,
                        label_verbalizations,
                        prompt_template_t,
                    )

                    # Pathway A: Zero-Shot
                    st.markdown("### 🎛️ Pathway A: Zero-Shot Predictions")
                    st.caption(
                        "Evaluating the model out-of-the-box without any additional training."
                    )
                    preds_zero = pipeline.predict(texts, batch_size=8)

                    for text, pred in zip(texts, preds_zero):
                        st.info(
                            f"**Text:** '{text}' ➔ **Prediction:** `{pred}`"
                        )

                    st.write("---")

                    # Pathway B: Label-Tuning
                    st.markdown("### 🏋️ Pathway B: Label-Tuning Fine-Tuning")
                    st.caption(
                        "Adapting the model's classification space using your provided ground truths."
                    )

                    with st.status(
                        "Training via label-tuning...", expanded=True
                    ) as status:
                        pipeline.fit(texts, truths)
                        status.update(
                            label="Fine-tuning complete!",
                            state="complete",
                            expanded=False,
                        )

                    preds_post = pipeline.predict(texts, batch_size=8)
                    for text, pred in zip(texts, preds_post):
                        st.success(
                            f"**Text:** '{text}' ➔ **Post-Training Prediction:** `{pred}`"
                        )

                except Exception as e:
                    st.error(f"An error occurred: {e}")
        else:
            st.info(
                "Configure the options on the left and click 'Run Text Pipelines'."
            )

